def _git_last_modified(repo_root: Path, file_path: Path) -> str | None:
    try:
        result = subprocess.run(['git', 'log', '--follow', '-1', '--format=%ai', str(file_path)],
            cwd=repo_root,
            capture_output=True,
            text=True,
            timeout=10,
        )
        out = result.stdout.strip()
        return out.split(" ")[0] if out else None
    except Exception:
        return None
